import { BatchItem, ExtractionResult } from '../types.ts'; // This relies on shared logic, in real app, separate
import * as extractor from './extractor.ts';
import * as settings from './settings.ts';
import AdmZip from 'adm-zip';
import sanitize from 'sanitize-filename';
import { Buffer } from 'buffer';

// Re-defining interface locally for strictness if types.ts isn't shared easily in XML structure
interface QueueItem {
    id: string;
    url: string;
    status: 'pending' | 'processing' | 'success' | 'failed';
    result?: any;
    retries: number;
}

let queue: QueueItem[] = [];
let isProcessing = false;

export function getStatus() {
    return { queue, isProcessing };
}

export function addItems(items: QueueItem[]) {
    queue.push(...items);
}

export function clearQueue() {
    if (!isProcessing) queue = [];
}

export async function startProcessing() {
    if (isProcessing) return;
    isProcessing = true;
    processQueue();
}

export function stopProcessing() {
    isProcessing = false;
}

async function processQueue() {
    const config = settings.get();
    const concurrency = config.concurrency || 1;

    while (isProcessing) {
        const pending = queue.find(i => i.status === 'pending');
        if (!pending) break; // Done

        // Super simple concurrency handling: just await one by one for this demo
        // To do real concurrency, we'd need a pool.

        pending.status = 'processing';

        try {
            // Rate limit delay
            const delay = 60000 / (config.rateLimit || 10);
            await new Promise(r => setTimeout(r, delay));

            const result = await extractor.extractSingle(pending.url);
            pending.result = {
                ...result,
                filename: generateFilename(result.title, 'Vol1', '01'), // Simplified
                wordCount: result.content.split(/\s+/).length
            };
            pending.status = 'success';
        } catch (e: any) {
            pending.status = 'failed';
            pending.result = { error: e.message };
            console.error(`Error processing ${pending.url}:`, e);
        }
    }
    isProcessing = false;
}

function generateFilename(title: string, vol: string, ch: string) {
    return sanitize(`${vol}-${ch} ${title}.txt`);
}

export async function createBatchZip() {
    const zip = new AdmZip();
    const successItems = queue.filter(i => i.status === 'success' && i.result);

    successItems.forEach(item => {
        if(item.result) {
            const content = `${item.result.title}\n${item.url}\n\n${item.result.content}`;
            const fname = sanitize(`${item.result.title.substring(0, 50)}.txt`);
            zip.addFile(fname, Buffer.from(content, 'utf8'));
        }
    });

    return zip.toBuffer();
}

import express from 'express';
import cors from 'cors';
import { json } from 'body-parser';
import * as extractor from './extractor.ts';
import * as queue from './queue.ts';
import * as templates from './templates.ts';
import * as settings from './settings.ts';
import path from 'path';

const app = express();
const PORT = 3000;

app.use(cors());
app.use(json());

// Helper for error handling
const asyncHandler = (fn: Function) => (req: express.Request, res: express.Response, next: express.NextFunction) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

// Single Extract
app.post('/api/extract', asyncHandler(async (req: express.Request, res: express.Response) => {
  const { url, templateId } = req.body;
  const result = await extractor.extractSingle(url, templateId);
  res.json(result);
}));

// Test Selectors
app.post('/api/extract/test-selectors', asyncHandler(async (req: express.Request, res: express.Response) => {
  const { url, titleSelector, contentSelector } = req.body;
  const result = await extractor.testSelectors(url, titleSelector, contentSelector);
  res.json(result);
}));

// Batch Operations
app.get('/api/batch/status', (req, res) => {
  try {
    res.json(queue.getStatus());
  } catch (e: any) {
    console.error("Batch status error:", e);
    res.status(500).json({ error: e.message });
  }
});

app.post('/api/batch/add', (req, res) => {
  try {
    queue.addItems(req.body.items);
    res.json({ success: true });
  } catch (e: any) {
    res.status(500).json({ error: e.message });
  }
});

app.post('/api/batch/start', (req, res) => {
  queue.startProcessing();
  res.json({ success: true });
});

app.post('/api/batch/stop', (req, res) => {
  queue.stopProcessing();
  res.json({ success: true });
});

app.post('/api/batch/clear', (req, res) => {
  queue.clearQueue();
  res.json({ success: true });
});

app.get('/api/batch/download', asyncHandler(async (req: express.Request, res: express.Response) => {
  const zipBuffer = await queue.createBatchZip();
  res.set('Content-Type', 'application/zip');
  res.set('Content-Disposition', 'attachment; filename=chapters.zip');
  res.send(zipBuffer);
}));

// Templates
app.get('/api/templates', (req, res) => {
  try {
    const data = templates.getAll();
    res.json(data);
  } catch (e: any) {
    console.error("Templates get error:", e);
    res.status(500).json({ error: e.message });
  }
});

app.post('/api/templates', (req, res) => {
  try {
    templates.save(req.body);
    res.json({ success: true });
  } catch (e: any) {
    console.error("Templates save error:", e);
    res.status(500).json({ error: e.message });
  }
});

app.delete('/api/templates/:id', (req, res) => {
  try {
    templates.remove(req.params.id);
    res.json({ success: true });
  } catch (e: any) {
    res.status(500).json({ error: e.message });
  }
});

// Settings
app.get('/api/settings', (req, res) => {
  try {
    const data = settings.get();
    res.json(data);
  } catch (e: any) {
    console.error("Settings get error:", e);
    res.status(500).json({ error: e.message });
  }
