import React, { useState, useEffect } from 'react';
import { AppSettings } from '../types';
import { Save, Settings as SettingsIcon, ToggleRight, ToggleLeft, AlertCircle } from 'lucide-react';

export default function Settings() {
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [saved, setSaved] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetch('/api/settings')
      .then(async res => {
        if (!res.ok) {
          const text = await res.text();
          throw new Error(`Server responded with ${res.status}: ${text}`);
        }
        return res.json();
      })
      .then(setSettings)
      .catch(err => setError(err.message));
  }, []);

  const handleSave = async () => {
    if (!settings) return;
    try {
      const res = await fetch('/api/settings', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify(settings)
      });

      if (!res.ok) throw new Error("Failed to save settings");

      setSaved(true);
      setTimeout(() => setSaved(false), 2000);
    } catch (err: any) {
      setError(err.message);
    }
  };

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-red-500 gap-4">
        <AlertCircle className="w-12 h-12" />
        <p className="font-mono text-sm">SYSTEM ERROR: {error}</p>
        <button 
          onClick={() => window.location.reload()}
          className="bg-white/10 px-4 py-2 hover:bg-white/20 text-white text-xs uppercase"
        >
          Retry Connection
        </button>
      </div>
    );
  }

  if (!settings) return <div className="text-katana font-mono animate-pulse p-10">INITIALIZING SYSTEM...</div>;

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in slide-in-from-bottom-5 duration-500">
      <div className="border-l-4 border-katana pl-4">
        <h2 className="text-3xl font-bold text-white tracking-tight uppercase flex items-center gap-3">
           System Configuration
        </h2>
        <p className="text-steel font-mono text-xs mt-1 tracking-wider">&gt;&gt; GLOBAL PARAMETER ADJUSTMENT</p>
      </div>

      <div className="bg-armor border border-white/10 p-8 relative overflow-hidden">
        {/* Background Element */}
        <SettingsIcon className="absolute -top-10 -right-10 w-64 h-64 text-white opacity-5 rotate-12" />

        <div className="relative z-10 space-y-10">
            {/* Performance Section */}
            <section>
              <h3 className="text-sm font-bold text-katana uppercase tracking-widest mb-6 border-b border-white/5 pb-2">Core Performance</h3>
              <div className="grid grid-cols-2 gap-8">
                 <div className="space-y-2">
                   <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Concurrency Thread Limit</label>
                   <input 
                      type="number" min="1" max="10"
                      value={settings.concurrency}
                      onChange={e => setSettings({...settings, concurrency: parseInt(e.target.value)})}
                      className="w-full bg-plate border border-white/10 p-3 text-white focus:border-katana focus:outline-none font-mono"
                   />
                   <p className="text-[10px] text-steel opacity-50 font-mono">&gt;&gt; SIMULTANEOUS OPERATIONS</p>
                 </div>
                 <div className="space-y-2">
                   <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Request Rate Limit</label>
                   <input 
                      type="number" min="1"
                      value={settings.rateLimit}
                      onChange={e => setSettings({...settings, rateLimit: parseInt(e.target.value)})}
                      className="w-full bg-plate border border-white/10 p-3 text-white focus:border-katana focus:outline-none font-mono"
                   />
                   <p className="text-[10px] text-steel opacity-50 font-mono">&gt;&gt; CALLS PER MINUTE</p>
                 </div>
              </div>
            </section>

            {/* Output Section */}
            <section>
               <h3 className="text-sm font-bold text-katana uppercase tracking-widest mb-6 border-b border-white/5 pb-2">Output Formatting</h3>
               <div className="space-y-6">
                  <div className="space-y-2">
                    <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Filename Schema</label>
                    <input 
