import fs from "node:fs";
import fsp from "node:fs/promises";
import path from "node:path";

export type Template = {
  id: string;
  name: string;
  domain?: string;
  titleSelector?: string;
  contentSelector?: string;
  removeSelectors?: string[];
  createdAt: number;
  updatedAt: number;
};

export type Settings = {
  concurrency: number;
  rateLimitPerMinute: number;
  outputDir: string;
  filenamePattern: string;
};

const dataDir = path.resolve(process.cwd(), "data");
const templatesPath = path.join(dataDir, "templates.json");
const settingsPath = path.join(dataDir, "settings.json");

const defaultSettings: Settings = {
  concurrency: 2,
  rateLimitPerMinute: 30,
  outputDir: path.resolve(process.cwd(), "exports"),
  filenamePattern: "{series}/{index} - {title}.txt",
};

async function ensureDir(p: string) {
  await fsp.mkdir(p, { recursive: true });
}

async function ensureFile(p: string, contents: string) {
  try {
    await fsp.access(p);
    const stat = await fsp.stat(p);
    if (stat.size === 0) {
      await fsp.writeFile(p, contents, "utf8");
    }
  } catch {
    await fsp.writeFile(p, contents, "utf8");
  }
}

function safeJsonParse<T>(raw: string, fallback: T): T {
  const t = raw.trim();
  if (!t) return fallback;
  try {
    return JSON.parse(t) as T;
  } catch {
    return fallback;
  }
}

export async function ensureStorage() {
  await ensureDir(dataDir);
  await ensureDir(defaultSettings.outputDir);
  await ensureFile(templatesPath, "[]");
  await ensureFile(settingsPath, JSON.stringify(defaultSettings, null, 2));
}

export async function readTemplates(): Promise<Template[]> {
  const raw = await fsp.readFile(templatesPath, "utf8");
  return safeJsonParse<Template[]>(raw, []);
}

export async function writeTemplates(templates: Template[]) {
  await fsp.writeFile(templatesPath, JSON.stringify(templates, null, 2), "utf8");
}

export async function readSettings(): Promise<Settings> {
  const raw = await fsp.readFile(settingsPath, "utf8");
  return safeJsonParse<Settings>(raw, defaultSettings);
}

export async function writeSettings(settings: Settings) {
  await ensureDir(settings.outputDir);
  await fsp.writeFile(settingsPath, JSON.stringify(settings, null, 2), "utf8");
}
```

